    atexit_insn_count++;
}

// F14: atexit drain. Fires when QEMU exits naturally (e.g. guest semihosting
// EXIT). The semihosting EXIT runs on the vCPU thread, so current_cpu is
// still set and qemu_plugin_read_register works. If any other trigger
// already drained, return immediately (drained_already guards against
// double drain). Inside an atexit handler, exit() is UB per C11 7.22.4.4;
// use _exit() to skip the rest of the atexit chain.
static void on_atexit(qemu_plugin_id_t id, void *udata)
{
    (void) id;
    (void) udata;
    if (drained_already) return;
    if (!drain_at_exit_mode) return;
    // pc=0 is a positive marker that the atexit path drained (no trigger).
    drain_state_to_file(0, 0, atexit_insn_count);
    fflush(stderr);
    _exit(200);

